public class TestRunner {
    static int passed = 0;
    static int failed = 0;

    public static void main(String[] args) {

        // в”Ђв”Ђ Item basics в”Ђв”Ђ
        try {
            Item potion = new Item("Health Potion", 20);
            check("Item.getName()",
                  "Health Potion", potion.getName());
        } catch (Exception e) { fail("Item.getName()", e); }

        try {
            Item potion = new Item("Health Potion", 20);
            check("Item.getPrice()",
                  "20", String.valueOf(potion.getPrice()));
        } catch (Exception e) { fail("Item.getPrice()", e); }

        try {
            Item bad = new Item("Cursed Ring", -5);
            check("Item price clamps negative to 0",
                  "0", String.valueOf(bad.getPrice()));
        } catch (Exception e) { fail("Item price clamp", e); }

        // в”Ђв”Ђ Character basics в”Ђв”Ђ
        try {
            Character hero = new Character("Aria", 50);
            check("Character.getName()",
                  "Aria", hero.getName());
        } catch (Exception e) { fail("Character.getName()", e); }

        try {
            Character hero = new Character("Aria", 50);
            check("Character.getGold()",
                  "50", String.valueOf(hero.getGold()));
        } catch (Exception e) { fail("Character.getGold()", e); }

        try {
            Character broke = new Character("Bob", -10);
            check("Character gold clamps negative to 0",
                  "0", String.valueOf(broke.getGold()));
        } catch (Exception e) { fail("Character gold clamp", e); }

        // в”Ђв”Ђ canAfford в”Ђв”Ђ
        try {
            Character hero = new Character("Aria", 50);
            Item potion = new Item("Potion", 20);
            check("canAfford() вЂ” has enough",
                  "true", String.valueOf(hero.canAfford(potion)));
        } catch (Exception e) { fail("canAfford() true", e); }

        try {
            Character hero = new Character("Aria", 10);
            Item sword = new Item("Sword", 25);
            check("canAfford() вЂ” not enough",
                  "false", String.valueOf(hero.canAfford(sword)));
        } catch (Exception e) { fail("canAfford() false", e); }

        try {
            Character hero = new Character("Aria", 20);
            Item potion = new Item("Potion", 20);
            check("canAfford() вЂ” exact amount",
                  "true", String.valueOf(hero.canAfford(potion)));
        } catch (Exception e) { fail("canAfford() exact", e); }

        // в”Ђв”Ђ buyItem вЂ” success в”Ђв”Ђ
        try {
            Character hero = new Character("Aria", 50);
            Item potion = new Item("Health Potion", 20);
            String result = hero.buyItem(potion);
            check("buyItem() success message",
                  "Aria buys Health Potion for 20 gold.", result);
        } catch (Exception e) { fail("buyItem() success message", e); }

        try {
            Character hero = new Character("Aria", 50);
            Item potion = new Item("Health Potion", 20);
            hero.buyItem(potion);
            check("buyItem() subtracts gold",
                  "30", String.valueOf(hero.getGold()));
        } catch (Exception e) { fail("buyItem() subtracts gold", e); }

        // в”Ђв”Ђ buyItem вЂ” failure в”Ђв”Ђ
        try {
            Character hero = new Character("Aria", 10);
            Item sword = new Item("Sword", 25);
            String result = hero.buyItem(sword);
            check("buyItem() failure message",
                  "Aria cannot afford Sword.", result);
        } catch (Exception e) { fail("buyItem() failure message", e); }

        try {
            Character hero = new Character("Aria", 10);
            Item sword = new Item("Sword", 25);
            hero.buyItem(sword);
            check("buyItem() failure doesn't change gold",
                  "10", String.valueOf(hero.getGold()));
        } catch (Exception e) { fail("buyItem() failure gold unchanged", e); }

        // в”Ђв”Ђ Multiple purchases в”Ђв”Ђ
        try {
            Character hero = new Character("Aria", 40);
            Item p = new Item("Potion", 15);
            Item s = new Item("Shield", 30);
            hero.buyItem(p);   // 40 - 15 = 25
            String r = hero.buyItem(s);  // 25 < 30 в†’ fail
            check("Second buy fails (not enough gold left)",
                  "Aria cannot afford Shield.", r);
        } catch (Exception e) { fail("Multiple purchases", e); }

        // в”Ђв”Ђ status() в”Ђв”Ђ
        try {
            Character hero = new Character("Aria", 50);
            check("status()",
                  "Aria has 50 gold.", hero.status());
        } catch (Exception e) { fail("status()", e); }

        try {
            Character hero = new Character("Aria", 50);
            hero.buyItem(new Item("Potion", 20));
            check("status() after purchase",
                  "Aria has 30 gold.", hero.status());
        } catch (Exception e) { fail("status() after purchase", e); }

        // в”Ђв”Ђ Encapsulation в”Ђв”Ђ
        try {
            java.lang.reflect.Field f = Character.class.getDeclaredField("gold");
            check("Character.gold is private", "true",
                  String.valueOf(java.lang.reflect.Modifier.isPrivate(f.getModifiers())));
        } catch (NoSuchFieldException e) {
            fail("Character.gold field exists", new Exception("Field 'gold' not found"));
        } catch (Exception e) { fail("Character.gold is private", e); }

        try {
            java.lang.reflect.Field f = Item.class.getDeclaredField("price");
            check("Item.price is private", "true",
                  String.valueOf(java.lang.reflect.Modifier.isPrivate(f.getModifiers())));
        } catch (NoSuchFieldException e) {
            fail("Item.price field exists", new Exception("Field 'price' not found"));
        } catch (Exception e) { fail("Item.price is private", e); }
    }

    static void check(String label, String expected, String actual) {
        if (expected.equals(actual)) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label
                + " \u2014 expected \"" + expected
                + "\" but got \"" + actual + "\""); failed++;
        }
    }
    static void fail(String label, Exception e) {
        System.out.println("FAIL: " + label + " \u2014 " + e.getMessage()); failed++;
    }
}
